head.script:
//전역변수
scwin.oilOilStatNo = "";
scwin.strCurDate = "";

scwin.isRetrieveTree = false; //TreeView의 데이터셋 조회여부
scwin.EXPEND_FG = 0;
scwin.preRow = 0;
scwin.viewMode = "S";
scwin.createRow = 0;
scwin.saveBranchCd = "";
scwin.dupChkOilStatNo = "";
scwin.isDupchk = false;
scwin.savePatternCd = "";

scwin.onpageload = function () {
    scwin.params = $c.data.getParameter();
    scwin.oilOilStatNo = scwin.params.oilStatNo || "";
    scwin.strCurDate = $c.date.getServerDateTime("yyyyMMdd");
    const codeOptions = [
        { grpCd: "TL108", compID: "lc_oilStatLvlClsCd" } // 셀렉트
        , { grpCd: "TL112", compID: "lc_clntClsCd" } // 셀렉트
        , { grpCd: "TL109", compID: "lc_bilgKndCd" }  // 부가세분기구분
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function () {
    lc_useYn.setValue(9);
    await scwin.f_retrieveOilStatInfoTree();
    scwin.f_ContentsDisable();

    if (scwin.oilOilStatNo != "") {
        ed_oilStatNo.setValue(scwin.oilOilStatNo);
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 화면 좌측 Tree데이타 조회
//-------------------------------------------------------------------------
scwin.f_retrieveOilStatInfoTree = async function () {
    scwin.isRetrieveTree = false;

    dma_oilStatInfoTreeCon.set("useYn", lc_useYn.getValue());
    dma_oilStatInfoTreeCon.set("qryConKnd", "ALL");

    ds_oilStatInfoTree.removeAll();
    var result = await $c.sbm.execute(sbm_retrieveOilStatInfoList);

    if (result.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        //for=ds_oilStatInfoTree event=OnLoadCompleted(rowCnt)
        var rowCnt = ds_oilStatInfoTree.getRowCount();
        scwin.isRetrieveTree = true;
        if (rowCnt > 0) {
            tv_oilStatInfoTree.spanNode(1, true, false);
            tv_oilStatInfoTree.findNodeByIndex(hid_tvIndex.getValue(), true);

        }
    } else {
        scwin.isRetrieveTree = false;
    }
};

//-------------------------------------------------------------------------
// 좌측 지점 트리 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    if (!await $c.gus.cfValidate([ed_oilStatNo])) {
        return;
    }
    var oilStatNo = ed_oilStatNo.getValue();

    if (ds_oilStatInfoTree.getMatchedIndex("oilOilStatNo", oilStatNo) > 0) { //if (ds_oilStatInfoTree.NameValueRow("oilOilStatNo", oilStatNo) > 0) {
        if (ds_oilStatInfoTree.getRowPosition() == ds_oilStatInfoTree.getMatchedIndex("oilOilStatNo", oilStatNo)) { //ds_oilStatInfoTree.NameValueRow("oilOilStatNo", oilStatNo)) {
            if (scwin.viewMode == "U" || scwin.viewMode == "C") {
                if (!await $c.win.confirm("현재 작업중 입니다. 취소 하시겠습니까?")) {
                    return;
                }
            }

            if (scwin.viewMode == "C" && ds_oilStatInfoTree.getRowStatus(scwin.createRow) == "C") {
                ds_oilStatInfoTree.deleteRow(scwin.createRow);
            }

            sub_title.setValue(ds_oilStatInfoTree.getCellData(ds_oilStatInfoTree.getRowPosition(), "oilStatNm"));
            scwin.f_getOilStatInfo(ds_oilStatInfoTree.getRowPosition());
            scwin.f_RetrieveOilStatInfo(ds_oilStatInfoTree.getRowPosition());

        } else {
            scwin.preRow = 0; //scwin.preRow = -1;

            // tobe추가:조회부분에 주유소 값이 있을시, 상위주유소펼쳐지고 해당 주유소로 포커스 셋팅
            var oilcd = ds_oilStatInfoTree.getMatchedJSON("oilOilStatNo", ed_oilStatNo.getValue());
            tv_oilStatInfoTree.expandNode(oilcd[0].upperOilStrPlcNo);
            tv_oilStatInfoTree.findNodeByValue(ed_oilStatNo.getValue(), true);


            ds_oilStatInfoTree.setRowPosition(ds_oilStatInfoTree.getMatchedIndex("oilOilStatNo", oilStatNo));
        }

        $c.gus.cfDisableBtn([b_Cancel2, b_Save2]);//$c.gus.cfDisableBtn([b_Cancel1, b_Cancel2, b_Save1, b_Save2]);
        $c.gus.cfEnableObjects([b_Create2, b_Update2]); //$c.gus.cfEnableObjects([b_Create1, b_Create2, b_Update1, b_Update2]);
    }
};

//-------------------------------------------------------------------------
// 지점  현황 조회
//-------------------------------------------------------------------------
scwin.f_RetrieveOilStatInfo = async function (row) {
    dma_oilStatInfoCon.set("oilOilStatNo", ds_oilStatInfoTree.getCellData(row, "oilOilStatNo"));

    ds_oilPch.removeAll();
    var result = await $c.sbm.execute(sbm_retrieveOilStatContentsList);

    //for=ds_oilPch event=OnLoadCompleted(rowcnt)
    if (result.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        var rowCnt = ds_oilPch.getRowCount();
        totalRows1.setValue(rowCnt)

    }
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Clear = async function (e) {
    var row = 0
    if (ds_oilStatInfoTree.getRowPosition() > 0) {
        row = ds_oilStatInfoTree.getRowPosition();
    }
    var oilStatNo = ds_oilStatInfoTree.getCellData(row, "oilOilStatNo");
    var oilStatNm = ds_oilStatInfoTree.getCellData(row, "oilStatNm");
    var curLevel = $c.num.parseInt(tv_oilStatInfoTree.getSelectedElement().lvl); //tv_oilStatInfoTree.ItemLevel;


    if (curLevel > 2) {
        await $c.gus.cfAlertMsg("지점 밑으로는 추가 할 수 없습니다.");
        return false;
    }
    if (!await $c.win.confirm(oilStatNm + "의 하위 점소를 새로 등록 하시겠습니까?")) {
        return;
    }

    var oilStatNm = curLevel == 0 ? "신규지사" : "신규지점"

    var rowJson = {
        "lvl": curLevel + 1,
        "oilStatNm": oilStatNm,
        "upperOilStrPlcNo": oilStatNo
    }

    if ((ds_oilStatInfoTree.getRowPosition() == ds_oilStatInfoTree.getRowCount() - 1) || (ds_oilStatInfoTree.getRowPosition() <= 0)) {
        // 처음이나 마지막 로우인 경우
        ds_oilStatInfoTree.setRowJSON(ds_oilStatInfoTree.getRowCount(), rowJson);

    } else {
        // 중간로우인 경우
        ds_oilStatInfoTree.setRowJSON(row + 1, rowJson);
    }

    scwin.createRow = ds_oilStatInfoTree.getRowPosition() <= 0 ? 0 : ds_oilStatInfoTree.getRowPosition();
    tv_oilStatInfoTree.findNodeByIndex(scwin.createRow + 2, true);

    scwin.viewMode = "C";
    $c.gus.cfInitObjects(tbl_content);
    chb_useYn.checkAll(true); //chb_useYn.checked = true;

    ed_opnOfcDt.setValue(scwin.strCurDate);
    ed_upperOilStrPlcNo.setValue(oilStatNo);
    txt_upperOilStrPlcNm.setValue(oilStatNm);
    scwin.f_ContentsEnable();
    txt_oilStatNo.focus();

    ds_oilPch.removeAll();

    sub_title.setValue("신규지점 등록");
    ed_oilStatNo.setValue("");
    txt_oilStatNm.setValue("");

    if (curLevel == 0) {
        scwin.savePatternCd = "S";
    } else if (curLevel == 1) {
        scwin.savePatternCd = "J";
    } else if (curLevel == 2) {
        scwin.savePatternCd = "O";
    } else {
        await $c.gus.cfAlertMsg("주유소 구분 코드  에러입니다.");
        return false;
    }

    lc_oilStatLvlClsCd.setValue(scwin.savePatternCd);
    lc_bilgKndCd.setValue("M");      // 청구종류 : 월단위청구

    $c.gus.cfDisableBtn([b_Create2, b_Update2]); //$c.gus.cfDisableBtn([b_Create1, b_Create2, b_Update1, b_Update2]);
    $c.gus.cfEnableObjects([b_Cancel2, b_Save2]); //$c.gus.cfEnableObjects([b_Cancel1, b_Cancel2, b_Save1, b_Save2]);
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = async function (e) {
    if (ds_oilStatInfoTree.getCellData(ds_oilStatInfoTree.getRowPosition(), "oilOilStatNo") == "AAA") {
        await $c.gus.cfAlertMsg("전체는 수정 할 수 없습니다.");
        return;
    }
    scwin.viewMode = "U";
    scwin.f_ContentsEnable();

    $c.gus.cfDisableBtn([b_Create2, b_Update2]); //$c.gus.cfDisableBtn([b_Create1, b_Create2, b_Update1, b_Update2]);
    $c.gus.cfEnableObjects([b_Cancel2, b_Save2]); //$c.gus.cfEnableObjects([b_Cancel1, b_Cancel2, b_Save1, b_Save2]);
};

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = async function (e) {
    var row = ds_oilStatInfoTree.getRowPosition();
    if (scwin.viewMode == "U") {
        if (scwin.isRetrieveTree) {
            if (!await $c.win.confirm("현재 작업중 입니다. 취소 하시겠습니까?")) {
                return;
            }
            sub_title.setValue(ds_oilStatInfoTree.getCellData(row, "oilStatNm"));
            scwin.f_getOilStatInfo(row);
            scwin.f_RetrieveOilStatInfo(row);
            scwin.viewMode = "S";
        }
        scwin.f_ContentsDisable();
    } else if (scwin.viewMode == "C") {
        scwin.preRow = 0;//scwin.preRow = -1;
        ds_oilStatInfoTree.setRowPosition(0);
    }

    $c.gus.cfDisableBtn([b_Cancel2, b_Save2]); //$c.gus.cfDisableBtn([b_Cancel1, b_Cancel2, b_Save1, b_Save2]);
    $c.gus.cfEnableObjects([b_Create2, b_Update2]); //$c.gus.cfEnableObjects([b_Create1, b_Create2, b_Update1, b_Update2]);
};

//-------------------------------------------------------------------------
// 중복체크
//-------------------------------------------------------------------------
scwin.f_chkOilStatNoDup = async function (e) {
    if (!await $c.gus.cfValidate([txt_oilStatNo])) {
        return;
    }
    scwin.isDupchk = false;

    scwin.dupChkOilStatNo = txt_oilStatNo.getValue();

    ds_chkOilStatNoDup.removeAll();
    var result = await $c.sbm.execute(sbm_retrieveOilStatInfoListByDupChk);

    //for=ds_chkOilStatNoDup event=OnLoadCompleted(rowCnt)
    if (result.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        if (ds_oilStatInfoTree.getMatchedIndex("oilOilStatNo", scwin.dupChkOilStatNo) > 0) {
            await $c.gus.cfAlertMsg(scwin.dupChkOilStatNo + "는 이미 등록된 점소코드 입니다.");
            scwin.isDupchk = false;
            //cfCopyDataSet(ds_chkOilStatNoDup, ds_oilStatInfoTree);
            //tv_oilStatInfoTree.reset();
        } else {
            scwin.isDupchk = true;
            await $c.gus.cfAlertMsg(scwin.dupChkOilStatNo + "는 등록 가능 합니다.");
        }
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (e) {
    if (!await $c.gus.cfValidate([txt_oilStatNo, txt_oilStatNm, ed_upperOilStrPlcNo, lc_oilStatLvlClsCd, lc_homeClsCd, lc_oilSelfClsCd, chb_spotsaleYn, ed_clntNo, ed_bilgAcctDeptCd
        , ed_stockAcctDeptCd, ed_opnOfcDt, txt_picNm, txt_telNo, chb_useYn, lc_oilTskClsCd, txt_telNo, lc_clntClsCd, txt_frchNoSh, ed_repClntNo])) {
        return;
    }

    //saveOilStatCd = txt_oilStatNo.value; //tobe 삭제 : 호출하는곳 미존재

    if (!await scwin.f_setOilStatInfo()) {
        return;
    }

    var oilStatNo = dma_oilStatInfoBySave.get(0, "oilOilStatNo");

    for (var i = 0; i < ds_oilPch.getRowCount(); i++) {
        if (ds_oilPch.getRowStatus(i) == "C") {
            ds_oilPch.setCellData(i, "oilOilStatNo", oilStatNo);
        }
    }

    if (scwin.viewMode == "U") {
        var result = await $c.sbm.execute(sbm_updateOilStatInfo);

        //for="tr_updateOilStatInfo" event="OnSuccess()
        if (result.responseJSON.resultDataSet[0].Msg != 'FAIL') {
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_retrieveOilStatInfoTree();
        }

    } else if (scwin.viewMode == "C") {
        if (!scwin.isDupchk || txt_oilStatNo.getValue() != scwin.dupChkOilStatNo) {
            await $c.gus.cfAlertMsg("중복체크를 하셔야 합니다.");
            return;
        }

        var result = await $c.sbm.execute(sbm_createOilStatInfo);

        //for="tr_createOilStatInfo" event="OnSuccess()"
        if (result.responseJSON.resultDataSet[0].Msg != 'FAIL') {
            await $c.gus.cfAlertMsg(MSG_CM_INF_001);
            scwin.f_retrieveOilStatInfoTree();
        }
    }
};

//-------------------------------------------------------------------------
// 항목 Disable
//-------------------------------------------------------------------------
scwin.f_ContentsDisable = function () {
    $c.gus.cfEnableObj(txt_oilStatNo, false);
    $c.gus.cfEnableObj(txt_oilStatNm, false);
    $c.gus.cfEnableObj(btn_oilStatNoDup, false);
    $c.gus.cfEnableObj(ed_upperOilStrPlcNo, false);
    $c.gus.cfEnableObj(txt_upperOilStrPlcNm, false);
    $c.gus.cfEnableObj(btn_upperOilStrPlcNo, false);
    $c.gus.cfEnableObj(lc_oilStatLvlClsCd, false);
    $c.gus.cfEnableObj(lc_homeClsCd, false);
    $c.gus.cfEnableObj(lc_oilSelfClsCd, false);
    $c.gus.cfEnableObj(chb_spotsaleYn, false);
    $c.gus.cfEnableObj(ed_clntNo, false);
    $c.gus.cfEnableObj(txt_clntNm, false);
    $c.gus.cfEnableObj(btn_clntNo, false);
    $c.gus.cfEnableObj(ed_repClntNo, false);
    $c.gus.cfEnableObj(txt_repClntNm, false);
    $c.gus.cfEnableObj(btn_repClntNo, false);
    $c.gus.cfEnableObj(ed_bilgAcctDeptCd, false);
    $c.gus.cfEnableObj(txt_bilgAcctDeptNm, false);
    $c.gus.cfEnableObj(btn_bilgAcctDeptCd, false);
    $c.gus.cfEnableObj(ed_stockAcctDeptCd, false);
    $c.gus.cfEnableObj(txt_stockAcctDeptNm, false);
    $c.gus.cfEnableObj(btn_stockAcctDeptCd, false);
    $c.gus.cfEnableObj(ed_opnOfcDt, false);
    //$c.gus.cfEnableObj(btn_opnOfcDt, false);
    $c.gus.cfEnableObj(ed_closOfcDt, false);
    //$c.gus.cfEnableObj(btn_closOfcDt, false);
    $c.gus.cfEnableObj(txt_picNm, false);
    $c.gus.cfEnableObj(txt_telNo, false);
    $c.gus.cfEnableObj(chb_useYn, false);
    $c.gus.cfEnableObj(lc_oilTskClsCd, false);
    $c.gus.cfEnableObj(txt_rmk, false);
    $c.gus.cfEnableObj(chb_dsaleYn, false);
    $c.gus.cfEnableObj(lc_clntClsCd, false); // 거래처구분
    $c.gus.cfEnableObj(txt_frchNoSh, false);
    $c.gus.cfEnableObj(lc_bilgKndCd, false);

    $c.gus.cfEnableObj(btn_addRow1, false);
    $c.gus.cfEnableObj(btn_deleteRow1, false);
    $c.gus.cfEnableObj(btn_cancelRow1, false);

    gr_oilPch.setGridReadOnly(true);
};

//-------------------------------------------------------------------------
// 항목 Disable
//-------------------------------------------------------------------------
scwin.f_ContentsEnable = function () {
    if (scwin.viewMode == "C") {
        $c.gus.cfEnableObj(txt_oilStatNo, true);
        $c.gus.cfEnableObj(btn_oilStatNoDup, true);
    }
    if (scwin.viewMode == "U") {
        $c.gus.cfEnableObj(ed_upperOilStrPlcNo, true);
        $c.gus.cfEnableObj(txt_upperOilStrPlcNm, true);
        $c.gus.cfEnableObj(btn_upperOilStrPlcNo, true);
        $c.gus.cfEnableObj(lc_oilStatLvlClsCd, true);
    }
    $c.gus.cfEnableObj(txt_oilStatNm, true);
    $c.gus.cfEnableObj(lc_homeClsCd, true);
    $c.gus.cfEnableObj(lc_oilSelfClsCd, true);
    $c.gus.cfEnableObj(chb_spotsaleYn, true);
    $c.gus.cfEnableObj(ed_clntNo, true);
    $c.gus.cfEnableObj(txt_clntNm, true);
    $c.gus.cfEnableObj(btn_clntNo, true);
    $c.gus.cfEnableObj(ed_repClntNo, true);
    $c.gus.cfEnableObj(txt_repClntNm, true);
    $c.gus.cfEnableObj(btn_repClntNo, true);
    $c.gus.cfEnableObj(ed_bilgAcctDeptCd, true);
    $c.gus.cfEnableObj(txt_bilgAcctDeptNm, true);
    $c.gus.cfEnableObj(btn_bilgAcctDeptCd, true);
    $c.gus.cfEnableObj(ed_stockAcctDeptCd, true);
    $c.gus.cfEnableObj(txt_stockAcctDeptNm, true);
    $c.gus.cfEnableObj(btn_stockAcctDeptCd, true);
    $c.gus.cfEnableObj(ed_opnOfcDt, true);
    //$c.gus.cfEnableObj(btn_opnOfcDt, true);
    $c.gus.cfEnableObj(ed_closOfcDt, true);
    //$c.gus.cfEnableObj(btn_closOfcDt, true);
    $c.gus.cfEnableObj(txt_picNm, true);
    $c.gus.cfEnableObj(txt_telNo, true);
    $c.gus.cfEnableObj(chb_useYn, true);
    $c.gus.cfEnableObj(lc_oilTskClsCd, true);
    $c.gus.cfEnableObj(txt_rmk, true);
    $c.gus.cfEnableObj(chb_dsaleYn, true);
    $c.gus.cfEnableObj(lc_clntClsCd, true); // 거래처구분
    $c.gus.cfEnableObj(txt_frchNoSh, true);
    $c.gus.cfEnableObj(lc_bilgKndCd, true);

    $c.gus.cfEnableObj(btn_addRow1, true);
    $c.gus.cfEnableObj(btn_deleteRow1, true);
    $c.gus.cfEnableObj(btn_cancelRow1, true);

    gr_oilPch.setGridReadOnly(false);
};

//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            // 정산귀속부서코드팝업
            udc_bilgAcctDept.cfCommonPopUp(
                function (rtnList) {
                    $c.gus.cfSetReturnValue(rtnList, ed_bilgAcctDeptCd, txt_bilgAcctDeptNm);  // 부서코드, 부서명
                },
                pCode.trim(),
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                null
            );
            break;

        case 2:
            // 재고귀속부서코드팝업
            udc_stockAcctDept.cfCommonPopUp(
                function (rtnList) {
                    $c.gus.cfSetReturnValue(rtnList, ed_stockAcctDeptCd, txt_stockAcctDeptNm);  // 부서코드, 부서명
                },
                pCode.trim(),
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                null
            );
            break;

        case 3:
            // 거래처코드팝업
            udc_clnt.cfCommonPopUp(
                function (rtnList) {
                    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, txt_clntNm);  // 거래처코드, 거래처명
                },
                pCode.trim(),
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                null
            );
            break;

        //tobe 삭제 : 호출부분 미존재
        // case 4:
        //     // 주유소팝업
        //     rtnList = cfCommonPopUp('retrieveFmsOilStationInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
        //     cfSetReturnValue(rtnList, ed_oilStatNo, txt_oilStaNm);  // 주유소코드, 주유소명
        //     break;

        // case 5:
        //     // 상위주유소팝업
        //     rtnList = cfCommonPopUp('retrieveFmsOilStationInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
        //     cfSetReturnValue(rtnList, ed_upperOilStrPlcNo, txt_upperOilStrPlcNm);  // 주유소코드, 주유소명
        //     break;

        // case 6:
        //     // 원가귀속부서코드팝업
        //     rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo', pCode.trim(), pName, pClose, null, null, null, null, null, null, null, null, null, null, pAllSearch, null);
        //     cfSetReturnValue(rtnList, ed_pcostAcctDeptCd, txt_pcostAcctDeptNm);  // 부서코드, 부서명
        //     break;

        case 7:
            // 대표거래처코드팝업
            udc_repClnt.cfCommonPopUp(
                function (rtnList) {
                    $c.gus.cfSetReturnValue(rtnList, ed_repClntNo, txt_repClntNm);  // 대표거래처코드, 거래처명
                },
                pCode.trim(),
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                null
            );
            break;

        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

